function parseMaybeJson(value, fallback = {}) {
  if (value && typeof value === "object") return value;

  if (typeof value !== "string") return fallback;

  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== "") {
      return value;
    }
  }
  return null;
}

const input = parseMaybeJson($json.payload, $json);

const ctx = input.execution_context || {};
const state = input.context_packet?.state || {};
const lead = input.context_packet?.lead || {};
const decisionStateUpdate = input.decision?.state_update || {};
const stateUpdate = ctx.state_update || input.state_update || decisionStateUpdate || {};

const leadId = firstValue(
  ctx.lead_id,
  lead.id,
  state.lead_id,
  input.lead_id
);

const channel = firstValue(
  ctx.channel,
  lead.channel,
  input.channel,
  "whatsapp"
);

const phone = firstValue(
  ctx.phone,
  lead.phone,
  input.phone
);

const bookingDate = firstValue(
  ctx.booking_date,
  decisionStateUpdate.booking_date,
  state.booking_date,
  input.booking_date
);

const bookingTime = firstValue(
  ctx.booking_time,
  decisionStateUpdate.booking_time,
  state.booking_time,
  input.booking_time
);

const slotId = firstValue(
  ctx.slot_id,
  decisionStateUpdate.slot_id,
  state.slot_id,
  bookingDate && bookingTime ? `${bookingDate}_${bookingTime}` : null
);

const serviceAddress = firstValue(
  ctx.service_address,
  ctx.address,
  decisionStateUpdate.service_address,
  decisionStateUpdate.address,
  state.service_address,
  state.address
);

const addressReference = firstValue(
  ctx.address_reference,
  decisionStateUpdate.address_reference,
  state.address_reference
);

const addressConfirmed =
  ctx.address_confirmed === true ||
  decisionStateUpdate.address_confirmed === true ||
  state.address_confirmed === true;

if (!leadId) {
  throw new Error("Missing execution_context.lead_id");
}

if (!channel) {
  throw new Error("Missing execution_context.channel");
}

if (!bookingDate) {
  throw new Error("Missing execution_context.booking_date");
}

if (!bookingTime) {
  throw new Error("Missing execution_context.booking_time");
}

const normalizedExecutionContext = {
  ...ctx,
  lead_id: leadId,
  phone,
  channel,
  action: "confirm_booking",

  service_interest: firstValue(ctx.service_interest, state.service_interest),
  vehicle_type: firstValue(ctx.vehicle_type, state.vehicle_type),
  district: firstValue(ctx.district, state.district),

  booking_date: bookingDate,
  booking_time: bookingTime,
  slot_id: slotId,
  availability_confirmed:
    ctx.availability_confirmed ??
    decisionStateUpdate.availability_confirmed ??
    state.availability_confirmed ??
    null,

  duration_minutes: Number(ctx.duration_minutes || state.duration_minutes || 120),
  calendar_id: firstValue(ctx.calendar_id, state.calendar_id, "primary"),

  service_address: serviceAddress,
  address: serviceAddress,
  address_reference: addressReference,
  address_confirmed: addressConfirmed,

  state_update: stateUpdate
};

return [{
  ...input,

  execution_context: normalizedExecutionContext,

  db_operations: ["appointments", "messages", "lead_state"],

  booking_request: {
    lead_id: leadId,
    channel,
    service_interest: normalizedExecutionContext.service_interest,
    vehicle_type: normalizedExecutionContext.vehicle_type,
    district: normalizedExecutionContext.district,
    booking_date: bookingDate,
    booking_time: bookingTime,
    slot_id: slotId,
    availability_confirmed: normalizedExecutionContext.availability_confirmed,
    duration_minutes: normalizedExecutionContext.duration_minutes,
    calendar_id: normalizedExecutionContext.calendar_id,
    service_address: serviceAddress,
    address_reference: addressReference,
    address_confirmed: addressConfirmed
  },

  state_update: {
    ...stateUpdate,
    last_bot_action: "confirm_booking_in_progress"
  }
}];

const start = $json.start_at ? new Date($json.start_at) : null;

const fecha = start
  ? start.toLocaleDateString("es-CL", {
      timeZone: "America/Santiago",
      weekday: "long",
      day: "2-digit",
      month: "long"
    })
  : "una fecha próxima";

const hora = start
  ? start.toLocaleTimeString("es-CL", {
      timeZone: "America/Santiago",
      hour: "2-digit",
      minute: "2-digit"
    })
  : "un horario confirmado";

return [{
  ...$json,
  message_to_send: `Ya tienes una reserva activa para el ${fecha} a las ${hora}. Si quieres, te ayudo a reprogramarla.`,
  db_operations: ["messages"],
  state_update: {
    ...($json.state_update || {}),
    last_bot_action: "booking_already_exists",
    next_goal: "reschedule_or_keep_booking"
  },
  notes: ["active_appointment_exists"]
}];

return [{
  ...$json,
  message_to_send: "Ese horario ya no está disponible. Si quieres, te propongo otro.",
  db_operations: ["messages"],
  state_update: {
    ...($json.state_update || {}),
    last_bot_action: "slot_unavailable",
    next_goal: "offer_new_booking_slot"
  },
  notes: ["slot_no_longer_available"]
}];

const event = $json.calendar_event || $json;
const ctx = $json.execution_context || {};
const lead = $json.context_packet?.lead || {};

if (!ctx.lead_id) {
  throw new Error("Missing execution_context.lead_id");
}

if (!event?.id) {
  throw new Error("Missing real calendar event id");
}

const startAt = event.start?.dateTime || event.start_at || null;
const endAt = event.end?.dateTime || event.end_at || null;

if (!startAt || !endAt) {
  throw new Error("Missing event start/end datetime");
}

return [{
  ...$json,
  appointment_payload: {
    event_id: event.id,
    conversation_id: ctx.lead_id,
    start_at: startAt,
    end_at: endAt,
    summary: event.summary || `${ctx.service_interest || "Servicio"} - ${lead.name || "Cliente"}`,
    description: event.description || "",
    status: "confirmed"
  }
}];

return [{
  ...$json,
  message_to_send: "No pude confirmar la reserva en este momento. Si quieres, lo reviso nuevamente o te propongo otro horario.",
  db_operations: ["messages"],
  state_update: {
    ...($json.state_update || {}),
    last_bot_action: "calendar_creation_failed",
    next_goal: "retry_booking_or_handoff"
  },
  notes: ["calendar_creation_failed"]
}];

function serviceLabel(service) {
  const map = {
    lavado_basico: "lavado básico",
    lavado_premium: "lavado premium",
    encerado_full: "encerado full",

    // Alias internos / antiguos
    lavado_profundo: "lavado premium",
    lavado_esencial: "lavado básico",
  };

  return map[service] || "el servicio";
}

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== "") {
      return value;
    }
  }
  return null;
}

const ctx = $json.execution_context || {};
const lead = $json.context_packet?.lead || {};
const appointment = $json.appointment_payload || {};
const calendarEvent = $json.calendar_event || {};

const startRaw =
  appointment.start_at ||
  calendarEvent.start?.dateTime ||
  $json.start_at ||
  null;

const start = startRaw ? new Date(startRaw) : null;

const fecha = start && !isNaN(start.getTime())
  ? start.toLocaleDateString("es-CL", {
      timeZone: "America/Santiago",
      weekday: "long",
      day: "2-digit",
      month: "long",
    })
  : firstValue(ctx.booking_date, $json.booking_date, "la fecha acordada");

const hora = start && !isNaN(start.getTime())
  ? start.toLocaleTimeString("es-CL", {
      timeZone: "America/Santiago",
      hour: "2-digit",
      minute: "2-digit",
      hour12: false,
    })
  : firstValue(ctx.booking_time, $json.booking_time, "el horario acordado");

const service = serviceLabel(
  firstValue(
    ctx.service_interest,
    $json.booking_context?.service_interest,
    $json.context_packet?.state?.service_interest
  )
);

const district = firstValue(
  ctx.district,
  $json.booking_context?.district,
  $json.context_packet?.state?.district
);

const address = firstValue(
  ctx.service_address,
  ctx.address,
  $json.booking_request?.service_address,
  $json.state_update?.service_address,
  $json.context_packet?.state?.service_address
);

const addressText = address
  ? ` en ${address}`
  : "";

const districtText = district
  ? ` en ${district}`
  : "";

const finalMessage =
  `Perfecto, tu reserva quedó confirmada para el ${fecha} a las ${hora}. ` +
  `Servicio: ${service}${districtText}${addressText}. ` +
  `Te escribiré antes de la visita para coordinar.`;

return [{
  ...$json,

  message_to_send: finalMessage,
  message: finalMessage,

  db_operations: ["appointments", "messages", "lead_state"],

  state_update: {
    ...($json.state_update || {}),
    stage: "booked",
    intent_last: "booking_confirmed",
    next_goal: "send_pre_service_instructions",
    last_bot_action: "confirm_booking",

    service_interest: firstValue(ctx.service_interest, $json.context_packet?.state?.service_interest),
    vehicle_type: firstValue(ctx.vehicle_type, $json.context_packet?.state?.vehicle_type),
    district,

    booking_date: firstValue(ctx.booking_date, $json.booking_date),
    booking_time: firstValue(ctx.booking_time, $json.booking_time),
    slot_id: firstValue(ctx.slot_id, $json.slot_id),

    availability_confirmed: true,

    service_address: address,
    address_reference: firstValue(
      ctx.address_reference,
      $json.booking_request?.address_reference,
      $json.state_update?.address_reference
    ),
    address_confirmed: true,

    last_appointment_event_id: firstValue(
      appointment.event_id,
      calendarEvent.id,
      $json.event_id
    ),

    missing_fields: [],
  },

  execution_result: {
    success: true,
    action: "confirm_booking",
    outcome: "booking_confirmed",
    bot: finalMessage,
    message_sent: false,
    state_updated: true,
    db_records_created: ["appointments", "messages", "lead_state"],
    notes: [
      ...($json.notes || []),
      "booking_confirmed_with_real_event"
    ]
  },

  notes: [
    ...($json.notes || []),
    "booking_confirmed_with_real_event"
  ]
}];

return [{
  ...$json,
  message_to_send: "La reserva en agenda se creó, pero hubo un problema al registrarla internamente. Lo revisaré antes de continuar.",
  db_operations: ["messages"],
  state_update: {
    ...($json.state_update || {}),
    last_bot_action: "appointment_insert_failed",
    next_goal: "manual_review_booking"
  },
  notes: ["appointment_insert_failed"]
}];

const action =
  $json.execution_context?.action ||
  $json.execution_result?.action ||
  "confirm_booking";

const records =
  $json.execution_result?.db_records_created ||
  $json.db_operations ||
  ["messages", "lead_state"];

return [{
  ...$json,

  execution_result: {
    success: $json.execution_result?.success !== false && $json.error !== true,
    action,
    message_sent: $json.message_sent === true,
    state_updated: true,
    db_records_created: records,
    notes: [
      ...($json.notes || []),
      ...($json.execution_result?.notes || []),
      "confirm_booking_subworkflow_done"
    ]
  }
}];

const data = $json;
const ctx = data.execution_context || {};
const state = data.context_packet?.state || {};

function firstText(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== "") {
      return String(value).trim();
    }
  }
  return null;
}

const serviceAddress = firstText(
  ctx.service_address,
  ctx.address,
  data.booking_request?.service_address,
  data.state_update?.service_address,
  state.service_address,
  state.address
);

const addressReference = firstText(
  ctx.address_reference,
  data.booking_request?.address_reference,
  data.state_update?.address_reference,
  state.address_reference
);

const addressConfirmed =
  ctx.address_confirmed === true ||
  data.booking_request?.address_confirmed === true ||
  data.state_update?.address_confirmed === true ||
  state.address_confirmed === true;

let addressGuardRoute = "continue_booking";
const notes = [...(data.notes || [])];

let stateUpdate = {
  ...(data.state_update || {}),
  ...(ctx.state_update || {})
};

if (!serviceAddress) {
  addressGuardRoute = "collect_address";

  stateUpdate = {
    ...stateUpdate,
    stage: "collecting_address",
    next_goal: "collect_address",
    last_bot_action: "collect_address",
    missing_fields: ["service_address"]
  };

  notes.push("booking_blocked_missing_service_address");
} else if (!addressConfirmed) {
  addressGuardRoute = "confirm_address";

  stateUpdate = {
    ...stateUpdate,
    stage: "address_confirmation",
    next_goal: "confirm_address",
    last_bot_action: "confirm_address_in_progress",
    service_address: serviceAddress,
    address_reference: addressReference,
    address_confirmed: false,
    missing_fields: []
  };

  notes.push("booking_blocked_address_not_confirmed");
} else {
  stateUpdate = {
    ...stateUpdate,
    service_address: serviceAddress,
    address_reference: addressReference,
    address_confirmed: true,
    missing_fields: []
  };

  notes.push("address_guard_passed");
}

return [{
  ...data,

  address_guard_route: addressGuardRoute,

  execution_context: {
    ...ctx,
    service_address: serviceAddress,
    address: serviceAddress,
    address_reference: addressReference,
    address_confirmed: addressConfirmed,
    state_update: stateUpdate
  },

  booking_request: {
    ...(data.booking_request || {}),
    service_address: serviceAddress,
    address_reference: addressReference,
    address_confirmed: addressConfirmed
  },

  state_update: stateUpdate,
  notes
}];

const ctx = $json.execution_context || {};

return [{
  ...$json,

  message_to_send:
    "Perfecto. Antes de confirmar la reserva necesito la dirección exacta donde se realizará el servicio. Puedes enviarme calle, número y alguna referencia.",

  db_operations: ["messages", "lead_state"],

  state_update: {
    ...($json.state_update || {}),
    stage: "collecting_address",
    next_goal: "collect_address",
    last_bot_action: "collect_address",
    missing_fields: ["service_address"],

    booking_date: ctx.booking_date,
    booking_time: ctx.booking_time,
    slot_id: ctx.slot_id,
    availability_confirmed: ctx.availability_confirmed,
    duration_minutes: ctx.duration_minutes,
    calendar_id: ctx.calendar_id
  },

  execution_context: {
    ...ctx,
    action: "collect_address"
  },

  execution_result: {
    success: true,
    action: "collect_address",
    message_sent: false,
    state_updated: true,
    db_records_created: ["messages", "lead_state"],
    notes: [
      ...($json.notes || []),
      "confirm_booking_paused_until_address"
    ]
  }
}];

